import random

def c(n):
    """Expected path length for a failed search in a BST of n nodes."""
    if n <= 1: return 0
    return 2 * (sum(1/i for i in range(1, n)) + 0.5772) - 2*(n-1)/n

class IsolationTree:
    def __init__(self, max_depth):
        self.max_depth = max_depth
        self.tree = None

    def fit(self, X, depth=0):
        n, d = len(X), len(X[0])
        if depth >= self.max_depth or n <= 1:
            return {'type': 'leaf', 'size': n}
        feat = random.randrange(d)
        lo   = min(x[feat] for x in X)
        hi   = max(x[feat] for x in X)
        if lo == hi:
            return {'type': 'leaf', 'size': n}
        split = random.uniform(lo, hi)
        left  = [x for x in X if x[feat] < split]
        right = [x for x in X if x[feat] >= split]
        return {
            'type': 'node', 'feat': feat, 'split': split,
            'left': self.fit(left, depth+1),
            'right': self.fit(right, depth+1)
        }

def path_length(x, node, depth=0):
    if node['type'] == 'leaf':
        return ___________
    if x[node['feat']] < node['split']:
        return path_length(x, node['left'],  depth+1)
    else:
        return path_length(x, node['right'], depth+1)

def anomaly_score(X_train, X_test, n_trees=50, max_depth=8):
    n = len(X_train)
    trees = []
    for _ in range(n_trees):
        t = IsolationTree(max_depth)
        sample = random.choices(X_train, k=min(256, n))
        trees.append(t.fit(sample))
    scores = []
    for x in X_test:
        avg_pl = sum(path_length(x, t) for t in trees) / n_trees
        scores.append(2 ** (-avg_pl / c(min(256, n))))
    return scores
